**Concise python Solution**
```
class TrieNode:
    def __init__(self, c):
        self.c = c
        self.children = {}
        self.isEnd = False
class Trie:
    def __init__(self):
        self.head = TrieNode('#')

    def insert(self,word):
        curs = self.head
        for c in word:
            if c not in curs.children:
                curs.children[c] = TrieNode(c)
            curs = curs.children[c]
        curs.isEnd = True

    def findWord(self, word):
        curs = self.head
        for c in word:
            if c not in curs.children:
                return False
            curs= curs.children[c]

        return curs.isEnd

    def findPref(self, pref):
        curs = self.head
        for c in pref:
            if c not in curs.children:
                return False
            curs = curs.children[c]

        return True

def findSubstrings(words, parts):   
    t = Trie()
    ret = []
    for part in parts: t.insert(part)
    for word in words:
        n = len(word)
        ll = []
        for i in range(n):
            for j in range(n, -1, -1):
                if t.findWord(word[i:j]):
                    ll.append(word[0:i] + '[' + word[i: j] + ']' + word[j:n])

        if not ll: ret.append(word)
        else :
            ll.sort(reverse=1, key=lambda x: x.find(']') - x.find('['))
            ret.append(ll[0])
    return ret
```

Python solution using Trie.
Time: O(num of words * avg length of word * avg length of part)
Space: O(num of parts * avg length of part) for Trie
```
END_MARK = '*'
class Trie:
    def __init__(self, c):
        self.c = c
        self.adjacentChars = {}

def findSubstrings(words, parts):
    # Prepare dictionary
    dictionary = {} # Total: Space O(num of parts * avg length of part) for Trie
    for part in parts: # Time O(num of parts * avg length of part)
        # Build Trie
        firstChar = part[0]
        if not firstChar in dictionary:
            dictionary[firstChar] = Trie(firstChar)
        node = dictionary[firstChar]
        for c in part[1:]:
            if not c in node.adjacentChars:
                node.adjacentChars[c] = Trie(c)
            node = node.adjacentChars[c]
        node.adjacentChars[END_MARK] = None

    def recursive(node, word, count): # Time O(avg length of part)
        if len(word) == 0:
            return count if END_MARK in node.adjacentChars else 0
        nextChar = word[0]
        if nextChar in node.adjacentChars:
            return recursive(node.adjacentChars[nextChar], word[1:], count + 1)
        else:
            return count

    # Total: Time O(num of words * avg length of word * avg length of part)
    output = {}
    for word in words: # Time O(num of words)
        output[word] = {}
        output[word]['length'] = -1
        output[word]['output'] = word
        length = len(word)
        for index, c in enumerate(word): # Time O(avg length of word)
            if length - 1 == index and word[index] in dictionary:
                moved = 0
            elif c in dictionary:
                moved = recursive(dictionary[c], word[index + 1:], 0)
            else:
                continue
            if moved > output[word]['length']:
                output[word]['length'] = moved
                output[word]['output'] = word[:index] + '[' + word[index: index + moved + 1] + ']' + word[index + moved + 1:]

    return [data['output'] for key, data in output.items()]

print(findSubstrings(["Apple", "Melon", "Orange", "Watermelon"], ["a", "App", "mel", "lon", "el", "An"]))

Output: ['[App]le', 'Me[lon]', 'Or[a]nge', 'Water[mel]on']
