public class Main {

    public static List<String> transform(String[] words, String[] parts) {
        HashSet<String> hs = new HashSet<String>();
        for (String part: parts) {
            hs.add(part);
        } 

        List<String> output = new ArrayList<String>();
        for (String word: words) {
            int first = -1;
            int last = -1;
            for (int i=0; i<word.length(); ++i) {
                for (int j=i+1; j<=word.length(); ++j) {
                    String sub = word.substring(i, j);
                    if (hs.contains(sub)) {
                        if ((first == -1 && last == -1) || ((last - first) < (j-i))) {
                            first = i;
                            last = j;
                        }
                    }
                }
            }
            if (first == -1) {
                output.add(word);
            }
            else {
                StringBuffer st = new StringBuffer();
                for (int i=0; i<word.length(); ++i) {
                    if (first == i) {
                        st.append('[');
                    }
                    st.append(word.charAt(i));
                    if ((last-1) == i) {
                        st.append(']');
                    }
                }
                output.add(st.toString());
            }
        }
        return output;
    }

    public static void main(String[] args) {
        String[] words = {"Apple", "Melon", "Orange", "Watermelon"};
        String[] parts = {"a", "mel", "lon", "el", "An"};
        List<String> output = transform(words, parts);
        System.out.println(output.toString());
    }
}
