We can use a Trie instead of the hashset as well. We can also do O(1) space by using indexOf for each word and part pair. Time complexity will vary. The optimal solution among these really depends on the dimensions of the inputs and which is more important to optimize time or space, which I guess is the conversation the interviewer must have wanted to have.

import java.util.*;

public class ScratchPad {
    private static final String END_MARK = "*";

    static class Trie {
        char c;
        Map<Character, Trie> adjacentChars;

        Trie(char c) {
            this.c = c;
            this.adjacentChars = new HashMap<Character, Trie>();
        }

        void addWord(String word) {
            Trie node = this;
            for (char ch : word.toCharArray()) {
                if (!node.adjacentChars.containsKey(ch)) {
                    node.adjacentChars.put(ch, new Trie(ch));
                }
                node = node.adjacentChars.get(ch);
            }
            node.adjacentChars.put(END_MARK.charAt(0), null); // Mark the end of a word
        }

        int findLongestSubstring(String word, int start) {
            Trie node = this;
            int length = 0;
            for (int i = start; i < word.length(); i++) {
                char ch = word.charAt(i);
                if (!node.adjacentChars.containsKey(ch)) {
                    break;
                }
                node = node.adjacentChars.get(ch);
                if (node.adjacentChars.containsKey(END_MARK.charAt(0))) {
                    length = i - start + 1;
                }
            }
            return length;
        }
    }

    static String[] findSubstrings(String[] words, String[] parts) {
        // Build Trie from parts
        Trie root = new Trie('\0');
        for (String part : parts) {
            root.addWord(part);
        }

        // Process each word
        String[] result = new String[words.length];
        for (int i = 0; i < words.length; i++) {
            result[i] = processWord(words[i], root);
        }

        return result;
    }

    private static String processWord(String word, Trie root) {
        int bestLength = 0;
        int bestPos = -1;
        for (int i = 0; i < word.length(); i++) {
            if (root.adjacentChars.containsKey(word.charAt(i))) {
                int curLength = root.findLongestSubstring(word, i);
                if (curLength > bestLength) {
                    bestLength = curLength;
                    bestPos = i;
                }
            }
        }

        if (bestLength > 0) {
            return word.substring(0, bestPos) + "[" + word.substring(bestPos, bestPos + bestLength) + "]" + word.substring(bestPos + bestLength);
        } else {
            return word;
        }
    }

    // Main method for testing
    public static void main(String[] args) {
        String[] words = {"Apple", "Melon", "Orange", "Watermelon"};
        String[] parts = {"a", "mel", "lon", "el", "An"};
        String[] parts2 = {"a", "App", "mel", "lon", "el", "An"};
        String[] modifiedWords = findSubstrings(words, parts);
        String[] modifiedWords2 = findSubstrings(words, parts2);
        System.out.println(Arrays.toString(modifiedWords));
        System.out.println(Arrays.toString(modifiedWords2));
    }
}


