Simple Java solution, passes all tests:
```java
String[] solution(String[] words, String[] parts) {  
    Set<String> set = new HashSet<String>(Arrays.asList(parts));  
    final String OPEN_BR = "[";
    final String CLOSE_BR = "]";
    for (int i = 0; i < words.length; i++) {
        String word = words[i];
        int len = word.length();
        for (int j = 5; j > 0; j--) {
            for (int k = 0; k <= len - j; k++) {
                String sub = word.substring(k, k + j);
                if (set.contains(sub)) {
                    words[i] = word.replaceFirst(sub, OPEN_BR + sub + CLOSE_BR);
                    j = -1; 
                    break;
                }
            }
        }
    }
    return words;
}
