function findSubstrings(words, parts) {
  const substrings = [];

  for (const w of words) {
    let res = w;
    let longest = 0;

    for (const p of parts) {
      const wParts = w.split(p);

      if (wParts.length > 1 && p.length > longest) {
        longest = p.length;
        res = `${wParts[0]}[${p}]${wParts[1]}`;
      }
    }

    substrings.push(res);
  }

  return substrings;
}
