public static String surroundString(String word, String [] parts){
    int start = -1;
    int maxLen = 0;
    for(String part : parts){
        if(word.indexOf(part) > -1 &&  maxLen < part.length()){
            start = word.indexOf(part);
            maxLen = part.length();
        }
        if(word.indexOf(part) > -1 && word.indexOf(part) < start && maxLen <= part.length() ){
            start = word.indexOf(part);
            maxLen = part.length();
        }
    }
    if(start == -1) return word;
    String subtr = word.substring(start, start + maxLen);
    return word.replace(subtr, "[" + subtr + "]") ;
}

