Here's the indexOf variation which uses O(1) space for good measure. Time is O(M*N*(m+n)). M = len of words array, N = len of parts array, m = len of longest word in words, n = len of longest part in parts.

```
public class Main {
    public static List<String> transform(String[] words, String[] parts) {
        List<String> output = new ArrayList<>();
        for (String word: words) {
            int maxLen = -1;
            int first = -1;
            int last = -1;
            for (String part: parts) {
                int ind = word.indexOf(part);
                if (ind >= 0) {
                    if (maxLen == -1 || part.length() > maxLen) {
                        maxLen = part.length();
                        first = ind;
                        last = ind+part.length();
                    }
                }
            }
            if (first == -1) {
                output.add(word);
            }
            else {
                StringBuffer st = new StringBuffer();
                for (int i=0; i<word.length(); ++i) {
                    if (first == i) {
                        st.append('[');
                    }
                    st.append(word.charAt(i));
                    if ((last-1) == i) {
                        st.append(']');
                    }
                }
                output.add(st.toString());
            }
        }
        return output;
    }

    public static void main(String[] args) {
        String[] words = {"Apple", "Melon", "Orange", "Watermelon"};
        String[] parts = {"a", "mel", "lon", "el", "An"};
        List<String> output = transform(words, parts);
        System.out.println(output.toString());
    }
